 		if (this._currentCommand.promptStartMarker && line >= this._currentCommand.promptStartMarker?.line) {
 			return this._cwd;
 		}
-		// TODO: It would be more reliable to take the closest cwd above the line if it isn't found for the line
+		// If the line is after the last known command finished, a new prompt has likely started
+		// that hasn't been tracked yet (eg. a race with the prompt start sequence), so the current
+		// cwd is more likely to be accurate than the last command's cwd.
+		const lastCommand = this._commands.length > 0 ? this._commands[this._commands.length - 1] : undefined;
+		if (lastCommand?.endMarker && line > lastCommand.endMarker.line) {
+			return this._cwd;
+		}
 		// TODO: Use a reverse for loop to find the line to avoid creating another array
 		const reversed = [...this._commands].reverse();
 		return reversed.find(c => c.marker!.line <= line - 1)?.cwd;

